 context.\n  db.workflow_state.push({\n    request_id: request.request_id,\n    account_id: request.account_id,\n    title: request.title,\n    status: request.expected_outcome,\n    next_step: request.next_step,\n    account_tier: account?.tier ?? null,\n    support_plan: contract?.support_plan ?? null,\n    arr_cents: contract?.arr_cents ?? null,\n    risk_signal_count: riskSignals.length,\n    recovery_owner: recoveryOwner ?? null,\n    opened_at: now\n  });\n\n  // Persist one open owner task per routed group, in routing order, with staggered SLAs.\n  ownerGroups.forEach((group, index) => {\n    const due = new Date(now);\n    due.setUTCHours(due.getUTCHours() + (index + 1) * 4);\n    db.owner_tasks.push({\n      request_id: request.request_id,\n      owner_group: group.owner_group,\n      title: `${group.owner_group} to drive recovery of ${request.title}`,\n      due_at: due.toISOString(),\n      status: \"open\",\n      created_at: now\n    });\n  });\n\n  // Persist the customer-safe message shown in the portal.\n  db.customer_messages.push({\n    request_id: request.request_id,\n    body: request.customer_message,\n    audience: \"customer\",\n    sent_at: now\n  });\n\n  // Persist a customer-visible audit event preserving the escalation timeline.\n  db.audit_events.push({\n    request_id: request.request_id,\n    event: \"at_risk_escalation_opened\",\n    summary: request.expected_outcome,\n    owner_routing: ownerGroups.map((group) => group.owner_group).join(\" + \"),\n    risk_signals: riskSignals.map((signal) => signal.signal_name).join(\", \"),\n    customer_visible: true,\n    recorded_at: now\n  });\n\n  return buildPortalView(db);\n}\n```\n\nAfter writing the file:\n1. Run `cd /Users/rom.iluz/Dev/sql-hidden-cost/benchmark/runs/ast-bench-v1/strategic-account-rescue/claude-code/repeat-1/postgres/workspace && npm test` and capture the FULL stdout/stderr.\n2. ALSO run the test directly to capture the true exit code (the npm wrapper may mask it): `cd /Us