ma/access-paths.md\\nschema/schema.md\\nsrc/portal-view.mjs\\nsrc/render-proof.mjs\\nsrc/workflow.mjs\\ntests-before.log\\ntests/acceptance.test.mjs\\n```\\n\\nThere are 5 directories: `data/`, `migrations/`, `schema/`, `src/`, `tests/`. No `node_modules`, no lockfile, no `.env` files. This is a self-contained, dependency-free Node ESM project.\\n\\n## 2. package.json (verbatim)\\n\\n```json\\n{\\n  \\\"name\\\": \\\"ast-bench-invoice-dispute-workflow-postgres\\\",\\n  \\\"version\\\": \\\"1.0.0\\\",\\n  \\\"private\\\": true,\\n  \\\"type\\\": \\\"module\\\",\\n  \\\"scripts\\\": {\\n    \\\"test\\\": \\\"node tests/acceptance.test.mjs\\\",\\n    \\\"render\\\": \\\"node src/render-proof.mjs\\\"\\n  }\\n}\\n```\\n\\nNo dependencies and no devDependencies — pure Node built-ins (`node:assert`, `node:fs`). `\\\"type\\\": \\\"module\\\"` so all `.mjs` use ESM imports.\\n\\n## 3. Test file (verbatim) — `tests/acceptance.test.mjs`\\n\\n```js\\nimport { deepStrictEqual, strictEqual } from \\\"node:assert\\\";\\nimport { readFileSync } from \\\"node:fs\\\";\\nimport { applyBenchmarkTask } from \\\"../src/workflow.mjs\\\";\\nimport { buildPortalView } from \\\"../src/portal-view.mjs\\\";\\n\\nconst now = \\\"2026-06-18T12:00:00.000Z\\\";\\nconst data = JSON.parse(readFileSync(new URL(\\\"../data/tables.json\\\", import.meta.url), \\\"utf8\\\"));\\nconst before = buildPortalView(structuredClone(data));\\nstrictEqual(before.status, \\\"Needs work\\\", \\\"Before state starts without the workflow\\\");\\nstrictEqual(before.history, \\\"Not visible\\\", \\\"Before state has no customer-visible audit trail\\\");\\nstrictEqual(before.tasks, \\\"0 owner tasks\\\", \\\"Before state has no owner tasks\\\");\\n\\nconst runData = structuredClone(data);\\nconst after = applyBenchmarkTask(runData, now);\\nconst expectedStatus = \\\"Invoice dispute active with finance owner, evidence bundle, and customer-safe status.\\\";\\nconst expectedOwners = data.workflow_request_owner_groups.slice(