tance.test.mjs\\\",\\n    \\\"render\\\": \\\"node src/render-proof.mjs\\\"\\n  }\\n}\\n```\\n\\nNo dependencies/devDependencies. `\\\"type\\\": \\\"module\\\"` (ESM). Tests run via plain `node`, no test framework.\\n\\n## 3. Test file (tests/acceptance.test.mjs) — full contents\\n\\nThis is the contract that must pass. Uses `node:assert`, reads `data/collections.json`, and imports `applyBenchmarkTask` from `src/workflow.mjs` and `buildPortalView` from `src/portal-view.mjs`.\\n\\nKey assertions:\\n- **Before state** (unmodified data through `buildPortalView`): `status === \\\"Needs work\\\"`, `history === \\\"Not visible\\\"`, `tasks === \\\"0 owner tasks\\\"`.\\n- **After state** (`applyBenchmarkTask(runData, now)` where `now = \\\"2026-06-18T12:00:00.000Z\\\"`):\\n  - `after.status === \\\"Invoice dispute active with finance owner, evidence bundle, and customer-safe status.\\\"`\\n  - `after.owner === expectedOwners.join(\\\" + \\\")` where `expectedOwners = data.workflow_requests[0].ownerGroups` = `\\\"Finance + Customer Success + Legal + Operations\\\"`\\n  - `after.nextStep.length > 8`\\n  - `after.history === \\\"Audit visible\\\"`\\n  - `after.customerMessage.length > 12`\\n  - `after.riskSummary === \\\"${expectedSignals.length} signals: ${names.join(\\\", \\\")}\\\"` = `\\\"6 signals: invoice, dispute, workflow, enterprise account, open customer impact, audit required\\\"`\\n  - `after.tasks === \\\"${expectedOwners.length} owner tasks\\\"` = `\\\"4 owner tasks\\\"`\\n- **Persisted-state assertions** (`assertPersistedState`) — `applyBenchmarkTask` must MUTATE `runData` in place:\\n  - `db.workflow_state` must contain a doc with `requestId === request._id` whose `status` equals expectedStatus and whose `riskSignals` (mapped to `.name`) deep-equal expected signal names.\\n  - `db.owner_tasks` must contain exactly `expectedOwners.length` (4) docs with `requestId === request._id`; their `ownerGroup` values must deep-equal `expectedOwners` (order matters: Finance, Customer Success, Legal, Operations); every task must have truthy `title`, truthy `dueAt`, and `status === \\\"open\\\"`.\\n  - `db.customer_messages` must contain a doc with matching `requestId` and truthy `body`.\\n  - `db.audit_events` must contain a doc with matching `requestId` and `customerVisible` truthy.\\n\\nThe full assertions reference `request._id` which is `\\\"invoice-invoice-disp\\\"` (note: NOT the same as `request.taskId`).\\n\\n## 4. Source files — full contents\\n\\n**src/workflow.mjs** (the stub to implement):\\n```js\\nimport { buildPortalView } from \\\"./portal-view.mjs\\\";\\n\\nexport function applyBenchmarkTask(db, now) {\\n  // TODO: Implement the benchmark workflow against the native data shape.\\n  return buildPortalView(db);\\n}\\n```\\n\\n**src/portal-view.mjs** (the read projection — DO NOT change; tests depend on it as-is):\\n```js\\nexport function buildPortalView(db) {\\n  const request = db.workflow_requests[0];\\n  const state = db.workflow_state.find((item) => item.requestId === request._id);\\n  const tasks = db.owner_tasks.filter((item) => item.requestId === request._id);\\n  const auditVisible = db.audit_events.some((item) => item.requestId === request._id && item.customerVisible);\\n  const message = db.customer_messages.find((item) => item.requestId === request._id);\\n\\n  return {\\n    taskId: request.taskId,\\n    title: state?.title || request.title,\\n    status: state?.status || \\\"Needs work\\\",\\n    owner: tasks.length ? tasks.map((item) => item.ownerGroup).join(\\\" + \\\") : \\\"Unassigned\\\",\\n    nextStep: state?.nextStep || \\\"Waiting for workflow\\\",\\n    riskSummary: state?.riskSignals?.length ? `${state.riskSignals.length} signals: ${state.riskSignals.map((item) => item.name).join(\\\", \\\")}` : \\\"Risk not scored\\\",\\n    tasks: `${tasks.length} owner tasks`,\\n    history: auditVisible ? \\\"Audit visible\\\" : \\\"Not visible\\\",\\n    customerMessage: message?.body || \\\"No customer-saf